function getFixedPlayersForTeam(teamName) {
  return fixedPlayerDatabase.filter(player =>
    player.teamName === teamName &&
    !player.startsAsFreeAgent
  );
}

function getFixedFreeAgents() {
  return fixedPlayerDatabase.filter(player =>
    player.startsAsFreeAgent ||
    player.teamName === "Free Agent"
  );
}

function getFixedPlayerById(playerId) {
  return fixedPlayerDatabase.find(player =>
    Number(player.playerId) === Number(playerId) ||
    Number(player.id) === Number(playerId)
  );
}

if (typeof window !== "undefined") {
  window.fixedPlayerDatabase = fixedPlayerDatabase;
  window.getFixedPlayersForTeam = getFixedPlayersForTeam;
  window.getFixedFreeAgents = getFixedFreeAgents;
  window.getFixedPlayerById = getFixedPlayerById;
}
